describe("Temporal.ZonedDateTime",()=>{describe("creation and parsing",()=>{it("can be created from an RFC 9557 string",()=>{let t=Temporal.ZonedDateTime.from("2021-08-19T17:01:00+01:00[Europe/London]");expect(t.toString()).toContain("2021-08-19T17:01:00+01:00[Europe/London]")}),it("can be created from an own object",()=>{let t=Temporal.ZonedDateTime.from("2021-08-19T17:01:00+01:00[Europe/London]"),o=Temporal.ZonedDateTime.from(t);expect(t).toEqual(o)}),it("can be created from an object containing properties",()=>{let t=Temporal.ZonedDateTime.from({timeZone:"America/Los_Angeles",year:1995,month:12,day:7,hour:3,minute:24,second:30,millisecond:0,microsecond:3,nanosecond:500});expect(t.toString()).toEqual("1995-12-07T03:24:30.0000035-08:00[America/Los_Angeles]")})}),describe("arithmetic methods",()=>{let t=Temporal.ZonedDateTime.from("2020-01-01T12:00:00+00:00[UTC]"),o=Temporal.ZonedDateTime.from("2020-01-02T12:00:00+00:00[UTC]");it("add() advances the date/time",()=>{let e=t.add({days:1});expect(e.day).toBe(2)}),it("compare() method works for two ZonedDateTime objects",()=>{expect(Temporal.ZonedDateTime.compare(t,o)).toBe(-1),expect(Temporal.ZonedDateTime.compare(o,t)).toBe(1),expect(Temporal.ZonedDateTime.compare(t,t)).toBe(0)}),it("equals() verifies if two ZonedDateTime are equal",()=>{let e=Temporal.ZonedDateTime.from("2020-01-01T12:00:00[UTC]");expect(t.equals(e)).toBe(!0)}),it("getTimeZoneTransition() returns the next and previous timezone offset transitions",()=>{let e=Temporal.ZonedDateTime.from("2024-01-01T00-05:00[America/New_York]"),n=e.getTimeZoneTransition("next");expect(n.toString()).toBe("2024-03-10T03:00:00-04:00[America/New_York]");let c=n.getTimeZoneTransition("next");expect(c.toString()).toBe("2024-11-03T01:00:00-05:00[America/New_York]");let i=e.getTimeZoneTransition("previous");expect(i.toString()).toBe("2023-11-05T01:00:00-05:00[America/New_York]");let r=Temporal.ZonedDateTime.from("2024-01-01T00Z[UTC]");expect(r.getTimeZoneTransition("next")).toBe(null)}),it("round() supports various forms, roundingMode, and roundingIncrement",()=>{let e=t.add({milliseconds:500}),n=e.round({smallestUnit:"second"});expect(n.second).toBe(1),expect(n.offset).toBe("+00:00"),expect(n.timeZoneId).toBe("UTC");let c=e.round({smallestUnit:"second",roundingMode:"trunc"});expect(c.second).toBe(0);let i=t.add({minutes:7,seconds:15}),r=i.round("minute");expect(r.minute).toBe(7),expect(r.second).toBe(0);let a=i.round({smallestUnit:"minute",roundingIncrement:15});expect(a.minute).toBe(0);let s=i.round({smallestUnit:"hour",roundingIncrement:2});expect(s.hour).toBe(12)}),it("since() returns correct duration",()=>{let e=o.since(t);expect(e.sign).toBe(1),expect(e.years).toBe(0),expect(e.months).toBe(0),expect(e.days).toBe(0),expect(e.hours).toBe(24),expect(e.minutes).toBe(0),expect(e.seconds).toBe(0),expect(e.milliseconds).toBe(0),expect(e.microseconds).toBe(0),expect(e.nanoseconds).toBe(0)}),it("subtract() decrements by a duration",()=>{let e=t.subtract({hours:1});expect(e.hour).toBeLessThan(t.hour)}),it("toInstant() returns a Temporal.Instant",()=>{let e=t.toInstant();expect(e).toBeInstanceOf(Temporal.Instant)}),it("toPlainDate() returns a Temporal.PlainDate",()=>{let e=t.toPlainDate();expect(e).toBeInstanceOf(Temporal.PlainDate),expect(e.toString()).toBe("2020-01-01")}),it("toPlainDateTime() returns a Temporal.PlainDateTime",()=>{let e=t.toPlainDateTime();expect(e).toBeInstanceOf(Temporal.PlainDateTime),expect(e.toString()).toBe("2020-01-01T12:00:00")}),it("toPlainTime() returns a Temporal.PlainTime",()=>{let e=t.toPlainTime();expect(e).toBeInstanceOf(Temporal.PlainTime),expect(e.toString()).toBe("12:00:00")}),it("toString() returns an ISO string representation",()=>{let e=t.toString();expect(typeof e).toBe("string"),expect(e).toBe("2020-01-01T12:00:00+00:00[UTC]")}),it("until() returns correct duration",()=>{let e=t.until(o);expect(e.sign).toBe(1),expect(e.years).toBe(0),expect(e.months).toBe(0),expect(e.days).toBe(0),expect(e.hours).toBe(24),expect(e.minutes).toBe(0),expect(e.seconds).toBe(0),expect(e.milliseconds).toBe(0),expect(e.microseconds).toBe(0),expect(e.nanoseconds).toBe(0)}),it("valueOf() throws a TypeError",()=>{expect(()=>{+t}).toThrow()}),it("with() method returns a new ZonedDateTime with updated fields",()=>{let e=t.with({day:15});expect(e.day).toBe(15),expect(e.month).toBe(t.month)}),it("withTimeZone() method returns a new ZonedDateTime with replaceing timezone",()=>{let e=t.withTimeZone("Asia/Tokyo");expect(e.toString()).toBe("2020-01-01T21:00:00+09:00[Asia/Tokyo]")})}),describe("properties",()=>{let t=Temporal.ZonedDateTime.from("2020-01-01T12:00:00[UTC]");it("should have correct date and time properties",()=>{expect(t.year).toBe(2020),expect(t.month).toBe(1),expect(t.day).toBe(1),expect(t.hour).toBe(12),expect(t.minute).toBe(0),expect(t.second).toBe(0),expect(t.millisecond).toBe(0),expect(t.offset).toBe("+00:00"),expect(typeof t.epochMilliseconds).toBe("number"),expect(t.epochMilliseconds).toBeGreaterThan(0),expect(typeof t.epochNanoseconds).toBe("bigint"),expect(t.epochNanoseconds).toBeGreaterThan(0n),expect(t.dayOfYear).toBe(1),expect(t.daysInMonth).toBe(31),expect(t.daysInYear).toBe(366),expect(t.inLeapYear).toBe(!0)}),it("has correct toStringTag",()=>{expect(Object.prototype.toString.call(t)).toBe("[object Temporal.ZonedDateTime]")})})});
